import java.util.*;

class Solution {
    public int[] solution(String[] id_list, String[] report, int k) {
        int n = id_list.length;
        Map<String, Integer> idxMap = new HashMap<>();
        for (int i = 0; i < n; i++) idxMap.put(id_list[i], i);

        // 각 피신고자를 신고한 사람 Set (중복 제거)
        Map<String, Set<String>> reportedBy = new HashMap<>();
        for (String id : id_list) reportedBy.put(id, new HashSet<>());

        for (String r : report) {
            String[] parts = r.split(" ");
            String reporter = parts[0], target = parts[1];
            reportedBy.get(target).add(reporter);
        }

        // k번 이상 신고된 사람 판별 후 신고자에게 이메일 카운트
        int[] answer = new int[n];
        for (String target : id_list) {
            Set<String> reporters = reportedBy.get(target);
            if (reporters.size() >= k) {
                for (String reporter : reporters) {
                    answer[idxMap.get(reporter)]++;
                }
            }
        }
        return answer;
    }
}

