class Solution {
    public int[] solution(int[] fees, String[] records) {
        int basTime = fees[0], baseFee = fees[1], unitTime = fees[2], unitFee = fees[3];
        Map<String, Integer> inTime = new HashMap<>();    // 현재 입차 시각
        Map<String, Integer> totalTime = new HashMap<>(); // 누적 주차 시간

        for (String record : records) {
            String[] parts = record.split(" ");
            int time = toMinutes(parts[0]);
            String carNum = parts[1];
            String status = parts[2];

            if (status.equals("IN")) {
                inTime.put(carNum, time);
                totalTime.putIfAbsent(carNum, 0);
            } else {
                int parked = time - inTime.remove(carNum);
                totalTime.merge(carNum, parked, Integer::sum);
            }
        }

        // 아직 IN 상태인 차량 23:59 처리
        for (Map.Entry<String, Integer> entry : inTime.entrySet()) {
            int parked = 1439 - entry.getValue();
            totalTime.merge(entry.getKey(), parked, Integer::sum);
        }

        // 차량 번호 오름차순 정렬
        List<String> sortedCars = new ArrayList<>(totalTime.keySet());
        Collections.sort(sortedCars);

        int[] answer = new int[sortedCars.size()];
        for (int i = 0; i < sortedCars.size(); i++) {
            int t = totalTime.get(sortedCars.get(i));
            if (t <= basTime) {
                answer[i] = baseFee;
            } else {
                int over = t - basTime;
                answer[i] = baseFee + (int) Math.ceil((double) over / unitTime) * unitFee;
            }
        }
        return answer;
    }

    private int toMinutes(String time) {
        String[] hm = time.split(":");
        return Integer.parseInt(hm[0]) * 60 + Integer.parseInt(hm[1]);
    }
}

class Solution {
    // 키패드 좌표: 1,2,3 → row0 / 4,5,6 → row1 / 7,8,9 → row2 / *,0,# → row3
    int[][] pad = {
        {3, 1}, // 0
        {0, 0}, // 1
        {0, 1}, // 2
        {0, 2}, // 3
        {1, 0}, // 4
        {1, 1}, // 5
        {1, 2}, // 6
        {2, 0}, // 7
        {2, 1}, // 8
        {2, 2}, // 9
    };

    public String solution(int[] numbers, String hand) {
        StringBuilder sb = new StringBuilder();
        int[] left = {3, 0};  // * 위치
        int[] right = {3, 2}; // # 위치

        for (int num : numbers) {
            int[] target = pad[num];
            if (num == 1 || num == 4 || num == 7) {
                sb.append('L');
                left = new int[]{target[0], target[1]};
            } else if (num == 3 || num == 6 || num == 9) {
                sb.append('R');
                right = new int[]{target[0], target[1]};
            } else {
                int distL = Math.abs(left[0] - target[0]) + Math.abs(left[1] - target[1]);
                int distR = Math.abs(right[0] - target[0]) + Math.abs(right[1] - target[1]);
                if (distL < distR || (distL == distR && hand.equals("left"))) {
                    sb.append('L');
                    left = new int[]{target[0], target[1]};
                } else {
                    sb.append('R');
                    right = new int[]{target[0], target[1]};
                }
            }
        }
        return sb.toString();
    }
}

