class Solution {
    public String solution(int n, int k, String[] cmd) {
        int[] prev = new int[n + 2];
        int[] next = new int[n + 2];
        // 인덱스 1~n이 실제 행(0-indexed+1), 0은 더미 헤드, n+1은 더미 테일
        for (int i = 0; i <= n + 1; i++) {
            prev[i] = i - 1;
            next[i] = i + 1;
        }

        int cur = k + 1; // 1-indexed
        Deque<Integer> deleted = new ArrayDeque<>();

        for (String c : cmd) {
            if (c.equals("C")) {
                deleted.push(cur);
                next[prev[cur]] = next[cur];
                prev[next[cur]] = prev[cur];
                cur = (next[cur] == n + 1) ? prev[cur] : next[cur];
            } else if (c.equals("Z")) {
                int restored = deleted.pop();
                next[prev[restored]] = restored;
                prev[next[restored]] = restored;
            } else {
                char dir = c.charAt(0);
                int x = Integer.parseInt(c.substring(2));
                for (int i = 0; i < x; i++) {
                    cur = (dir == 'U') ? prev[cur] : next[cur];
                }
            }
        }

        // 결과 생성 (1-indexed → 0-indexed)
        boolean[] alive = new boolean[n];
        int node = next[0]; // 더미 헤드 다음부터
        while (node != n + 1) {
            alive[node - 1] = true;
            node = next[node];
        }
        StringBuilder sb = new StringBuilder();
        for (boolean a : alive) sb.append(a ? 'O' : 'X');
        return sb.toString();
    }
}

