class Solution {
    Map<String, Integer> countMap = new HashMap<>();

    public String[] solution(String[] orders, int[] course) {
        List<String> result = new ArrayList<>();

        for (int len : course) {
            countMap.clear();
            for (String order : orders) {
                char[] arr = order.toCharArray();
                Arrays.sort(arr);
                combination(arr, new StringBuilder(), 0, len);
            }
            if (countMap.isEmpty()) continue;
            int maxCount = Collections.max(countMap.values());
            if (maxCount >= 2) {
                for (Map.Entry<String, Integer> e : countMap.entrySet()) {
                    if (e.getValue() == maxCount) result.add(e.getKey());
                }
            }
        }

        Collections.sort(result);
        return result.toArray(new String[0]);
    }

    private void combination(char[] arr, StringBuilder current, int start, int remain) {
        if (remain == 0) {
            countMap.merge(current.toString(), 1, Integer::sum);
            return;
        }
        for (int i = start; i <= arr.length - remain; i++) {
            current.append(arr[i]);
            combination(arr, current, i + 1, remain - 1);
            current.deleteCharAt(current.length() - 1);
        }
    }
}

