class Solution {
    public long solution(String expression) {
        List<Long> nums = new ArrayList<>();
        List<Character> ops = new ArrayList<>();
        StringBuilder sb = new StringBuilder();
        for (char c : expression.toCharArray()) {
            if (c == '+' || c == '-' || c == '*') {
                nums.add(Long.parseLong(sb.toString()));
                sb.setLength(0);
                ops.add(c);
            } else {
                sb.append(c);
            }
        }
        nums.add(Long.parseLong(sb.toString()));

        char[] operators = {'+', '-', '*'};
        long maxVal = 0;

        // 3! = 6가지 순열
        int[][] perms = {{0,1,2},{0,2,1},{1,0,2},{1,2,0},{2,0,1},{2,1,0}};
        for (int[] perm : perms) {
            List<Long> n = new ArrayList<>(nums);
            List<Character> o = new ArrayList<>(ops);
            for (int p : perm) {
                char op = operators[p];
                for (int i = 0; i < o.size(); ) {
                    if (o.get(i) == op) {
                        long result = calc(n.get(i), n.get(i + 1), op);
                        n.set(i, result);
                        n.remove(i + 1);
                        o.remove(i);
                    } else {
                        i++;
                    }
                }
            }
            maxVal = Math.max(maxVal, Math.abs(n.get(0)));
        }
        return maxVal;
    }

    private long calc(long a, long b, char op) {
        if (op == '+') return a + b;
        if (op == '-') return a - b;
        return a * b;
    }
}

class Solution {
    public String solution(String p) {
        return transform(p);
    }

    private String transform(String w) {
        if (w.isEmpty()) return "";

        // u: 가장 짧은 균형 접두사 분리
        int balance = 0, splitIdx = 0;
        for (int i = 0; i < w.length(); i++) {
            balance += (w.charAt(i) == '(') ? 1 : -1;
            if (balance == 0) { splitIdx = i + 1; break; }
        }
        String u = w.substring(0, splitIdx);
        String v = w.substring(splitIdx);

        if (isCorrect(u)) {
            return u + transform(v);
        } else {
            String inner = u.substring(1, u.length() - 1);
            StringBuilder reversed = new StringBuilder();
            for (char c : inner.toCharArray()) {
                reversed.append(c == '(' ? ')' : '(');
            }
            return "(" + transform(v) + ")" + reversed.toString();
        }
    }

    private boolean isCorrect(String s) {
        int count = 0;
        for (char c : s.toCharArray()) {
            if (c == '(') count++;
            else count--;
            if (count < 0) return false;
        }
        return true;
    }
}

