class Solution {
    public int[] solution(String s) {
        // 바깥쪽 {{ }} 제거: s = "{{...}}" → 내부 파싱
        // 각 집합을 중괄호 단위로 분리
        List<int[]> sets = new ArrayList<>();
        int depth = 0;
        StringBuilder cur = new StringBuilder();

        for (int i = 1; i < s.length() - 1; i++) { // 바깥 {} 제외
            char c = s.charAt(i);
            if (c == '{') {
                depth++;
                cur.setLength(0);
            } else if (c == '}') {
                depth--;
                if (depth == 0 && cur.length() > 0) {
                    String content = cur.toString();
                    String[] parts = content.split(",");
                    int[] set = new int[parts.length];
                    for (int j = 0; j < parts.length; j++) set[j] = Integer.parseInt(parts[j]);
                    sets.add(set);
                    cur.setLength(0);
                }
            } else if (depth > 0) {
                cur.append(c);
            }
        }

        // 크기 오름차순 정렬
        sets.sort(Comparator.comparingInt(a -> a.length));

        // 튜플 복원
        Set<Integer> seen = new HashSet<>();
        int[] answer = new int[sets.size()];
        int idx = 0;
        for (int[] set : sets) {
            for (int num : set) {
                if (seen.add(num)) {
                    answer[idx++] = num;
                    break;
                }
            }
        }
        return answer;
    }
}

