class Solution {
    public int solution(int[][] board, int[] moves) {
        int n = board.length;
        int[] topRow = new int[n];

        Stack<Integer> basket = new Stack<>();
        int count = 0;

        for (int move : moves) {
            int col = move - 1; // 0-indexed
            int doll = 0;
            while (topRow[col] < n) {
                if (board[topRow[col]][col] != 0) {
                    doll = board[topRow[col]][col];
                    board[topRow[col]][col] = 0;
                    topRow[col]++;
                    break;
                }
                topRow[col]++;
            }
            if (doll == 0) continue;

            if (!basket.isEmpty() && basket.peek() == doll) {
                basket.pop();
                count += 2;
            } else {
                basket.push(doll);
            }
        }
        return count;
    }
}

class Solution {
    public String[] solution(int n, int[] arr1, int[] arr2) {
        String[] answer = new String[n];
        for (int i = 0; i < n; i++) {
            int combined = arr1[i] | arr2[i];
            StringBuilder sb = new StringBuilder();
            for (int bit = n - 1; bit >= 0; bit--) {
                sb.append(((combined >> bit) & 1) == 1 ? '#' : ' ');
            }
            answer[i] = sb.toString();
        }
        return answer;
    }
}

class Solution {
    public int solution(String dartResult) {
        int[] scores = new int[3];
        int idx = 0, round = 0;

        while (idx < dartResult.length()) {
            // 숫자 파싱 (10은 두 자리)
            int num;
            if (dartResult.charAt(idx) == '1'
                    && idx + 1 < dartResult.length()
                    && dartResult.charAt(idx + 1) == '0') {
                num = 10;
                idx += 2;
            } else {
                num = dartResult.charAt(idx) - '0';
                idx++;
            }

            // 보너스
            char bonus = dartResult.charAt(idx++);
            if (bonus == 'D') num = num * num;
            else if (bonus == 'T') num = num * num * num;

            // 옵션
            if (idx < dartResult.length()
                    && (dartResult.charAt(idx) == '*' || dartResult.charAt(idx) == '#')) {
                char opt = dartResult.charAt(idx++);
                if (opt == '*') {
                    num *= 2;
                    if (round > 0) scores[round - 1] *= 2;
                } else {
                    num = -num;
                }
            }

            scores[round++] = num;
        }
        return scores[0] + scores[1] + scores[2];
    }
}

