class Solution {
    public int[] solution(int N, int[] stages) {
        int[] stageCount = new int[N + 2];
        for (int s : stages) stageCount[s]++;

        double[] failRate = new double[N + 1];
        int reached = stages.length;

        for (int i = 1; i <= N; i++) {
            if (reached == 0) {
                failRate[i] = 0;
            } else {
                failRate[i] = (double) stageCount[i] / reached;
            }
            reached -= stageCount[i];
        }

        Integer[] stageOrder = new Integer[N];
        for (int i = 0; i < N; i++) stageOrder[i] = i + 1;

        Arrays.sort(stageOrder, (a, b) -> {
            if (Double.compare(failRate[b], failRate[a]) != 0)
                return Double.compare(failRate[b], failRate[a]);
            return a - b;
        });

        int[] answer = new int[N];
        for (int i = 0; i < N; i++) answer[i] = stageOrder[i];
        return answer;
    }
}

