class Solution {
    public boolean solution(String[] phone_book) {
        Arrays.sort(phone_book);
        for (int i = 0; i < phone_book.length - 1; i++) {
            if (phone_book[i + 1].startsWith(phone_book[i])) {
                return false;
            }
        }
        return true;
    }

    // 방법2: HashSet 접두어 검사 (O(N * L^2))
    public boolean solution2(String[] phone_book) {
        Set<String> set = new HashSet<>(Arrays.asList(phone_book));
        for (String phone : phone_book) {
            for (int len = 1; len < phone.length(); len++) {
                if (set.contains(phone.substring(0, len))) {
                    return false;
                }
            }
        }
        return true;
    }
}

class Solution {
    public String solution(String m, String[] musicinfos) {
        String normalizedM = normalize(m);
        String answer = "(None)";
        int maxTime = -1;

        for (int i = 0; i < musicinfos.length; i++) {
            String[] parts = musicinfos[i].split(",");
            int startMin = toMinutes(parts[0]);
            int endMin = toMinutes(parts[1]);
            String title = parts[2];
            String sheet = normalize(parts[3]);

            int playTime = endMin - startMin;

            // 재생 시간만큼 악보 생성
            StringBuilder sb = new StringBuilder();
            while (sb.length() < playTime) sb.append(sheet);
            String played = sb.substring(0, playTime);

            if (played.contains(normalizedM)) {
                // 재생시간 더 길거나 같으면 먼저 나온 것 유지 (이미 maxTime과 같으면 갱신 안 함)
                if (playTime > maxTime) {
                    maxTime = playTime;
                    answer = title;
                }
            }
        }
        return answer;
    }

    private String normalize(String s) {
        return s.replace("C#", "c")
                .replace("D#", "d")
                .replace("F#", "f")
                .replace("G#", "g")
                .replace("A#", "a");
    }

    private int toMinutes(String time) {
        String[] hm = time.split(":");
        return Integer.parseInt(hm[0]) * 60 + Integer.parseInt(hm[1]);
    }
}
